-- STEG 3: import av saknade inskrifter ur rundata.sql (landskap Nä, 39 rader).
-- 39 kandidatrader. id = rundatas objectid (UUID) => spegeltabeller matchar.
-- Dedup: WHERE NOT EXISTS på signum + ON CONFLICT(id). Ren data, idempotent. Kör i editorn.
insert into public.runic_inscriptions
